// Adzuna — 250 req/month → run once daily at 8h
// FR (3 queries) + rotating country (2 queries) = 5/day × 30 = 150/month
const hour = new Date().getHours();
if (hour !== 8) return [{ json: { results: [], count: 0, _skipped: 'Adzuna: not scheduled this hour' } }];

const frQueries = ['computer vision', 'machine learning', 'deep learning'];
const intlQueries = ['computer vision', 'machine learning'];

// Rotate international country by day of week
const day = new Date().getDay();
const countries = { 0: 'gb', 1: 'de', 2: 'nl', 3: 'at', 4: 'us', 5: 'ca', 6: 'au' };
const intlCountry = countries[day];

const appId = $env.ADZUNA_APP_ID;
const appKey = $env.ADZUNA_KEY;
const allResults = [];

// France
for (const q of frQueries) {
  try {
    const url = `https://api.adzuna.com/v1/api/jobs/fr/search/1?app_id=${appId}&app_key=${appKey}&results_per_page=20&what=${encodeURIComponent(q)}&max_days_old=3&content-type=application/json`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (resp.results) allResults.push(...resp.results);
  } catch(e) {}
}

// Rotating international
console.log(`[Adzuna] Rotating country today: ${intlCountry}`);
for (const q of intlQueries) {
  try {
    const url = `https://api.adzuna.com/v1/api/jobs/${intlCountry}/search/1?app_id=${appId}&app_key=${appKey}&results_per_page=20&what=${encodeURIComponent(q)}&max_days_old=3&content-type=application/json`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (resp.results) allResults.push(...resp.results);
  } catch(e) {}
}

return [{ json: { results: allResults, count: allResults.length } }];

// SerpAPI — 100 req/month, 3 queries/run → run once daily at 20h
// 3-day cycle: FR → CH → UK → FR → ... = 3/day × 30 = 90/month
const hour = new Date().getHours();
if (hour !== 20) return [{ json: { jobs_results: [], count: 0, _skipped: 'SerpAPI: not scheduled this hour' } }];

const day = new Date().getDay();
const locations = [
  { location: 'Paris,+France', gl: 'fr', hl: 'fr' },
  { location: 'Zurich,+Switzerland', gl: 'ch', hl: 'en' },
  { location: 'London,+United+Kingdom', gl: 'gb', hl: 'en' }
];
const loc = locations[day % 3];
console.log(`[SerpAPI] Searching: ${loc.location}`);

const queries = [
  'computer vision engineer',
  'machine learning engineer',
  'software engineer python'
];

const apiKey = $env.SERPAPI_KEY;
const allJobs = [];

for (const q of queries) {
  try {
    const url = `https://serpapi.com/search.json?engine=google_jobs&q=${encodeURIComponent(q)}&location=${loc.location}&hl=${loc.hl}&gl=${loc.gl}&chips=date_posted:3days&api_key=${apiKey}`;
    const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (response.jobs_results) {
      allJobs.push(...response.jobs_results);
    }
  } catch(e) {
    // Skip failed queries
  }
}

return [{ json: { jobs_results: allJobs, count: allJobs.length } }];

// Normalize jobs from all 6 sources into a common format
let adzunaItems = [];
try { adzunaItems = $('Adzuna Job Search').first().json.results || []; } catch(e) {}
let serpItems = [];
try { serpItems = $('Google Jobs via SerpAPI').first().json.jobs_results || []; } catch(e) {}
let ftItems = [];
try { ftItems = $('France Travail').first().json.results || []; } catch(e) {}
let remotiveItems = [];
try { remotiveItems = $('Remotive').first().json.jobs || []; } catch(e) {}
let arbeitnowItems = [];
try { arbeitnowItems = $('Arbeitnow').first().json.data || []; } catch(e) {}
let jsearchItems = [];
try { jsearchItems = $('JSearch').first().json.data || []; } catch(e) {}

const jobs = [];
const seen = new Set();

function dedupKey(title, company) {
  return `${(title || '').toLowerCase().trim()}|${(company || '').toLowerCase().trim()}`;
}

// Adzuna
for (const job of adzunaItems) {
  const key = dedupKey(job.title, job.company?.display_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company?.display_name || '',
    location: job.location?.display_name || '',
    description: job.description || '',
    url: job.redirect_url || '',
    salary_min: job.salary_min || null,
    salary_max: job.salary_max || null,
    source: 'Adzuna',
    date_posted: job.created || '',
  });
}

// Google Jobs (SerpAPI)
for (const job of serpItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.location || '',
    description: job.description || '',
    url: job.apply_options?.[0]?.link || job.share_link || '',
    salary_min: null,
    salary_max: null,
    salary_text: job.detected_extensions?.salary || null,
    source: 'Google Jobs',
    date_posted: job.detected_extensions?.posted_at || '',
  });
}

// France Travail
for (const job of ftItems) {
  const key = dedupKey(job.intitule, job.entreprise?.nom);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.intitule || '',
    company: job.entreprise?.nom || '',
    location: job.lieuTravail?.libelle || '',
    description: job.description || '',
    url: job.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${job.id}`,
    salary_min: null,
    salary_max: null,
    salary_text: job.salaire?.libelle || null,
    source: 'France Travail',
    date_posted: job.dateCreation || '',
  });
}

// Remotive
for (const job of remotiveItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.candidate_required_location || 'Remote',
    description: job.description || '',
    url: job.url || '',
    salary_min: null,
    salary_max: null,
    salary_text: job.salary || null,
    source: 'Remotive',
    date_posted: job.publication_date || '',
  });
}

// Arbeitnow
for (const job of arbeitnowItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.location || (job.remote ? 'Remote' : ''),
    description: job.description || '',
    url: job.url || `https://www.arbeitnow.com/view/${job.slug}`,
    salary_min: null,
    salary_max: null,
    source: 'Arbeitnow',
    date_posted: job.created_at ? new Date(job.created_at * 1000).toISOString() : '',
  });
}

// JSearch (LinkedIn, Indeed, Glassdoor aggregated)
for (const job of jsearchItems) {
  const key = dedupKey(job.job_title, job.employer_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.job_title || '',
    company: job.employer_name || '',
    location: [job.job_city, job.job_state, job.job_country].filter(Boolean).join(', '),
    description: job.job_description || '',
    url: job.job_apply_link || '',
    salary_min: job.job_min_salary || null,
    salary_max: job.job_max_salary || null,
    source: 'JSearch',
    date_posted: job.job_posted_at_datetime_utc || '',
  });
}

console.log(`[Normalize] Adzuna(${adzunaItems.length}) SerpAPI(${serpItems.length}) FranceTravail(${ftItems.length}) Remotive(${remotiveItems.length}) Arbeitnow(${arbeitnowItems.length}) JSearch(${jsearchItems.length}) => ${jobs.length} unique`);

return jobs.map(j => ({ json: j }));

// Filter out already-processed jobs + deduplicate within batch

// Build dedup set from existing sheet rows
const existingKeys = new Set();
let sheetRowCount = 0;

try {
  const sheetItems = $('Read Existing Jobs').all();
  sheetRowCount = sheetItems.length;
  for (const item of sheetItems) {
    const d = item.json;
    if (!d || Object.keys(d).length === 0) continue;
    const role = String(d['Role'] || d['role'] || '').toLowerCase().trim();
    const company = String(d['Company'] || d['company'] || '').toLowerCase().trim();
    const location = String(d['Location'] || d['location'] || '').toLowerCase().trim();
    if (role || company) existingKeys.add(`${role}|${company}|${location}`);
  }
} catch(e) {
  console.log('[Filter] WARNING: Could not read existing jobs: ' + e.message);
}

const allNormalized = $('Normalize & Deduplicate').all();

// Deduplicate WITHIN this batch (Normalize may run multiple times due to n8n
// executing once per source connection — this removes the duplicates)
const batchSeen = new Set();
const newJobs = allNormalized.filter(item => {
  const j = item.json;
  const key = `${(j.title || '').toLowerCase().trim()}|${(j.company || '').toLowerCase().trim()}|${(j.location || '').toLowerCase().trim()}`;

  // Skip duplicates within this batch
  if (batchSeen.has(key)) return false;
  batchSeen.add(key);

  // Skip if already in sheet
  if (existingKeys.has(key)) return false;
  return true;
});

console.log(`[Filter] Input: ${allNormalized.length} (with dupes) | Unique: ${batchSeen.size} | In sheet: ${existingKeys.size} | New: ${newJobs.length}`);

if (newJobs.length === 0) return [];
return newJobs;

// ── Regex-based Role Categorization & Scoring (no LLM) ──────────────────────
const job = $input.item.json;
const title = (job.title || '').toLowerCase();
const desc = (job.description || '').toLowerCase();
const text = title + ' ' + desc;

// ── 1. Categorize by keywords (checked in priority order) ───────────────────
const categories = [
  {
    name: 'Computer Vision',
    keywords: [
      'computer vision', 'vision par ordinateur', 'traitement d\'image',
      'image processing', 'visual computing', 'perception visuelle',
      '3d vision', 'point cloud', 'nuage de points', 'lidar',
      'slam', 'depth estimation', 'stereo vision', 'object detection',
      'image recognition', 'video analysis', 'segmentation',
      'photogrammetry', 'photogramm\u00e9trie', 'reconstruction 3d',
      'vision engineer', 'ing\u00e9nieur vision'
    ],
    titleKeywords: ['vision', 'perception', '3d', 'image']
  },
  {
    name: 'Machine Learning Engineer',
    keywords: [
      'machine learning', 'deep learning', 'apprentissage profond',
      'apprentissage automatique', 'neural network', 'r\u00e9seau de neurones',
      'pytorch', 'tensorflow', 'mlops', 'ml engineer', 'ml ops',
      'ai engineer', 'artificial intelligence', 'intelligence artificielle',
      'nlp', 'llm', 'transformers', 'reinforcement learning',
      'mod\u00e8le ia', 'ia g\u00e9n\u00e9rative', 'generative ai'
    ],
    titleKeywords: ['machine learning', 'deep learning', 'ml ', ' ai ', 'ia ', 'artificial intelligence']
  },
  {
    name: 'Data Scientist',
    keywords: [
      'data scientist', 'data science', 'science des donn\u00e9es',
      'research scientist', 'chercheur', 'statistiques',
      'mod\u00e9lisation', 'experimentation', 'a/b test'
    ],
    titleKeywords: ['data scientist', 'research scientist', 'chercheur']
  },
  {
    name: 'Data Analyst',
    keywords: [
      'data analyst', 'data analysis', 'analyse de donn\u00e9es',
      'business intelligence', 'bi analyst', 'analytics',
      'tableau', 'power bi', 'reporting', 'analyste donn\u00e9es'
    ],
    titleKeywords: ['data analyst', 'analyste', 'analytics', 'bi ']
  }
];

let roleCategory = 'Software Engineer'; // fallback

// Title-based match has priority (more precise)
for (const cat of categories) {
  if (cat.titleKeywords.some(kw => title.includes(kw))) {
    roleCategory = cat.name;
    break;
  }
}
// If still fallback, try description keywords
if (roleCategory === 'Software Engineer') {
  for (const cat of categories) {
    const matchCount = cat.keywords.filter(kw => text.includes(kw)).length;
    if (matchCount >= 2) {
      roleCategory = cat.name;
      break;
    }
  }
}

// ── 2. Score: role relevance (higher = more relevant to my profile) ─────────
const roleScores = {
  'Computer Vision': 8,
  'Machine Learning Engineer': 6,
  'Data Scientist': 4,
  'Data Analyst': 3,
  'Software Engineer': 2
};
let score = roleScores[roleCategory] || 2;

// Contract type bonus/penalty
const contractPatterns = {
  cdi: /\b(cdi|full[- ]?time|permanent|unbefristet|temps plein|ind\u00e9termin\u00e9e?)\b/i,
  cdd: /\b(cdd|fixed[- ]?term|d\u00e9termin\u00e9e?|temporary|temporaire)\b/i,
  freelance: /\b(freelance|free[- ]?lance|ind\u00e9pendant|auto[- ]?entrepreneur|mission)\b/i,
  intern: /\b(stage|stagiaire|intern(ship)?|alternance|apprenti(ce|ssage)?|werkstudent|pratique)\b/i
};

let contractType = 'CDI';
if (contractPatterns.intern.test(text)) {
  contractType = 'Stage/Alternance';
  score -= 1;
} else if (contractPatterns.cdd.test(text)) {
  contractType = 'CDD';
} else if (contractPatterns.freelance.test(text)) {
  contractType = 'Freelance';
} else {
  score += 2;
}

// Location bonus: Paris > France > Europe > rest
const loc = (job.location || '').toLowerCase();
if (/paris|ile.de.france|idf|hauts.de.seine|92|75|la d\u00e9fense|boulogne|nanterre|levallois|puteaux|issy/i.test(loc)) {
  score += 3;
} else if (/france|lyon|marseille|toulouse|bordeaux|nantes|strasbourg|lille|montpellier|grenoble|nice/i.test(loc)) {
  score += 2;
} else if (/suisse|switzerland|zurich|z\u00fcrich|geneva|gen\u00e8ve|bern|basel|lausanne|uk|london|berlin|amsterdam|dublin|munich|m\u00fcnchen|remote/i.test(loc)) {
  score += 1;
}

// Clamp to 1-15
score = Math.max(1, Math.min(15, score));

// ── 3. Map category to pre-made resume Drive link ───────────────────────────
const resumeLinks = {
  'Computer Vision': $env.CV_LINK_COMPUTER_VISION || '',
  'Machine Learning Engineer': $env.CV_LINK_ML_ENGINEER || '',
  'Data Scientist': $env.CV_LINK_DATA_SCIENTIST || '',
  'Data Analyst': $env.CV_LINK_DATA_ANALYST || '',
  'Software Engineer': $env.CV_LINK_SOFTWARE_ENGINEER || ''
};

return {
  json: {
    ...job,
    role_category: roleCategory,
    contract_type: contractType,
    relevance_score: score,
    resume_link: resumeLinks[roleCategory]
  }
};

// Prepare row for Google Sheet with category and score
const job = $input.item.json;

// Format: yyyy-mm-dd hh:MM
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const hours = String(now.getHours()).padStart(2, '0');
const minutes = String(now.getMinutes()).padStart(2, '0');
const dateTime = `${year}-${month}-${day} ${hours}:${minutes}`;

return {
  json: {
    'Date': dateTime,
    'Company': job.company || '',
    'Role': job.title || '',
    'Location': job.location || '',
    'Source': job.source || '',
    'Date Posted': job.date_posted || '',
    'Apply URL': job.url || '',
    'Role Category': job.role_category || '',
    'Contract Type': job.contract_type || '',
    'Score': job.relevance_score || 0,
    'Resume PDF': job.resume_link || '',
    'Status': 'New',
    'Notes': ''
  }
};

// Daily digest — only send at 8am Paris time
const hour = new Date().getHours();
if (hour !== 8) return [];

const items = $('Prepare Sheet Row').all();
if (items.length === 0) return [];

const date = new Date().toLocaleDateString('fr-FR');

// Sort by score descending
const sorted = [...items].sort((a, b) => (b.json['Score'] || 0) - (a.json['Score'] || 0));

function formatPostedDate(raw) {
  if (!raw) return '-';
  if (isNaN(Date.parse(raw))) return raw;
  const d = new Date(raw);
  return d.toLocaleDateString('fr-FR');
}

function scoreColor(s) {
  if (s >= 8) return '#2d5016';
  if (s >= 5) return '#b8860b';
  return '#888';
}

const rows = sorted.map(item => {
  const d = item.json;
  const s = d['Score'] || 0;
  return `<tr><td style="padding:6px 10px;border-bottom:1px solid #eee"><strong style="color:${scoreColor(s)}">${s}/10</strong></td><td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Role Category']}</td><td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Company']}</td><td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Role']}</td><td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Location']}</td><td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Contract Type'] || '-'}</td><td style="padding:6px 10px;border-bottom:1px solid #eee"><a href="${d['Apply URL']}">Apply</a></td></tr>`;
}).join('');

return [{
  json: {
    emailSubject: `Job Pipeline: ${items.length} new jobs (${date})`,
    emailBody: `<div style="font-family:Arial,sans-serif;max-width:900px"><h2 style="color:#333">Job Pipeline Run Summary</h2><p><strong>${items.length}</strong> new jobs found, sorted by relevance score.</p><table style="border-collapse:collapse;width:100%;font-size:14px"><tr style="background:#2d5016;color:white"><th style="padding:8px 10px;text-align:left">Score</th><th style="padding:8px 10px;text-align:left">Category</th><th style="padding:8px 10px;text-align:left">Company</th><th style="padding:8px 10px;text-align:left">Role</th><th style="padding:8px 10px;text-align:left">Location</th><th style="padding:8px 10px;text-align:left">Contract</th><th style="padding:8px 10px;text-align:left">Apply</th></tr>${rows}</table><br><p style="color:#888;font-size:12px">Sent by your Job Search Automation Pipeline</p></div>`
  }
}];

// France Travail (Pole Emploi) — Official French job board
// Register at https://francetravail.io for client credentials
const clientId = $env.FRANCE_TRAVAIL_CLIENT_ID;
const clientSecret = $env.FRANCE_TRAVAIL_CLIENT_SECRET;

if (!clientId || !clientSecret) {
  console.log('[FranceTravail] No credentials, skipping');
  return [{ json: { results: [], count: 0 } }];
}

// Get OAuth2 token
let token;
try {
  const authResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://entreprise.francetravail.fr/connexion/oauth2/access_token?realm=/partenaire',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=client_credentials&client_id=${encodeURIComponent(clientId)}&client_secret=${encodeURIComponent(clientSecret)}&scope=api_offresdemploiv2%20o2dsoffre`,
  });
  const parsed = typeof authResp === 'string' ? JSON.parse(authResp) : authResp;
  token = parsed.access_token;
} catch(e) {
  console.log('[FranceTravail] Auth failed: ' + e.message);
  return [{ json: { results: [], count: 0 } }];
}

const queries = [
  'computer vision',
  'machine learning',
  'deep learning',
  'ingenieur logiciel',
  'vision par ordinateur',
  'data scientist',
  'intelligence artificielle',
  'ingenieur python'
];

const allResults = [];
for (const q of queries) {
  try {
    const url = `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?motsCles=${encodeURIComponent(q)}&range=0-24&publieeDepuis=3`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: { 'Authorization': `Bearer ${token}` },
      json: true
    });
    if (resp.resultats) allResults.push(...resp.resultats);
  } catch(e) { /* skip */ }
}

return [{ json: { results: allResults, count: allResults.length } }];

// Remotive — Free remote tech jobs API (no auth needed)
const categories = ['software-dev', 'data'];
const allJobs = [];
const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000; // last 7 days

for (const cat of categories) {
  try {
    const url = `https://remotive.com/api/remote-jobs?category=${cat}&limit=50`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (resp.jobs) {
      const recent = resp.jobs.filter(j => new Date(j.publication_date).getTime() >= cutoff);
      allJobs.push(...recent);
    }
  } catch(e) { /* skip */ }
}

return [{ json: { jobs: allJobs, count: allJobs.length } }];

// Arbeitnow — Free EU tech jobs API (no auth needed)
// Strict filter: focus on Computer Vision / AI R&D roles

const REQUIRED_TITLE_KEYWORDS = [
  'computer vision', 'vision engineer', 'cv engineer',
  'machine learning engineer', 'ml engineer',
  'ai engineer', 'artificial intelligence engineer',
  'deep learning engineer', 'research engineer',
  'r&d engineer', 'applied scientist', 'computer vision scientist'
];

const REQUIRED_STACK_KEYWORDS = [
  'computer vision', 'image processing', 'opencv', 'pytorch',
  'tensorflow', 'deep learning', 'machine learning', 'artificial intelligence',
  'neural network', 'segmentation', 'object detection', 'slam',
  '3d vision', 'point cloud', 'lidar', 'reconstruction', 'diffusion'
];

const EXCLUDE_TITLE_KEYWORDS = [
  'copywriter', 'content', 'social media', 'community manager',
  'customer success', 'account manager', 'sales', 'vertrieb',
  'außendienst', 'closer', 'chatsetter', 'country manager',
  'assistenz', 'werkstudent', 'praktikum', 'intern', 'grocery associate'
];

const EXCLUDE_DESC_KEYWORDS = [
  'customer success', 'social media', 'copywriting', 'outbound sales',
  'inside sales', 'field sales', 'account executive', 'business development'
];

function hasAny(text, words) {
  return words.some(w => text.includes(w));
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.arbeitnow.com/api/job-board-api',
    json: true
  });

  const cutoff = Math.floor(Date.now() / 1000) - 3 * 24 * 60 * 60;

  const filtered = (resp.data || []).filter(j => {
    if (j.created_at < cutoff) return false;

    const title = (j.title || '').toLowerCase();
    const desc = (j.description || '').toLowerCase();
    const tags = ((j.tags || []).join(' ') || '').toLowerCase();
    const text = `${title} ${desc} ${tags}`;

    // Hard reject obvious non-target profiles
    if (hasAny(title, EXCLUDE_TITLE_KEYWORDS) || hasAny(desc, EXCLUDE_DESC_KEYWORDS)) return false;

    // Strong accept: explicit target role in title
    if (hasAny(title, REQUIRED_TITLE_KEYWORDS)) return true;

    // Secondary accept: AI/CV stack density + engineering signal in title
    const stackHits = REQUIRED_STACK_KEYWORDS.filter(k => text.includes(k)).length;
    const hasEngineerSignal = /\b(engineer|scientist|research|r&d|developer|ingénieur)\b/i.test(title);

    return hasEngineerSignal && stackHits >= 3;
  });

  return [{ json: { data: filtered, count: filtered.length } }];
} catch(e) {
  return [{ json: { data: [], count: 0 } }];
}

// JSearch (RapidAPI) — 500 req/month, 2 queries/run → run every 3h
const hour = new Date().getHours();
if (hour % 3 !== 0) return [{ json: { data: [], count: 0, _skipped: 'JSearch: not scheduled this hour' } }];

const apiKey = $env.RAPIDAPI_KEY;

if (!apiKey) {
  console.log('[JSearch] No RAPIDAPI_KEY set, skipping');
  return [{ json: { data: [], count: 0 } }];
}

// Rotate queries across regions
const regionSets = [
  ['computer vision engineer in France', 'machine learning engineer in France'],
  ['computer vision engineer in Switzerland', 'software engineer python in Zurich'],
  ['machine learning engineer in London', 'computer vision engineer in UK'],
  ['deep learning engineer in Germany', 'AI engineer in Berlin'],
  ['computer vision engineer in France', 'machine learning engineer in France'],
  ['software engineer in Switzerland', 'AI engineer in Netherlands'],
  ['machine learning engineer in France', 'computer vision engineer in Germany'],
  ['deep learning engineer in UK', 'software engineer python in France']
];
const queries = regionSets[Math.floor(hour / 3) % regionSets.length];

const allJobs = [];
for (const q of queries) {
  try {
    const url = `https://jsearch.p.rapidapi.com/search?query=${encodeURIComponent(q)}&page=1&num_pages=1&date_posted=3days`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: {
        'X-RapidAPI-Key': apiKey,
        'X-RapidAPI-Host': 'jsearch.p.rapidapi.com'
      },
      json: true
    });
    if (resp.data) allJobs.push(...resp.data);
  } catch(e) { /* skip */ }
}

return [{ json: { data: allJobs, count: allJobs.length } }];
